MountConfig = {}

function MountConfig:init()
    local settings = FileUtil.getConfigFromCsv("setting/Mount.csv")
    for _, setting in pairs(settings) do
        local item = MountSetting.new()
        item.id = tonumber(setting.Id)
        item.size = VectorUtil.newVector3(setting.SizeX, setting.SizeY, setting.SizeZ)
        item.sensitivity = tonumber(setting.Sensitivity)
        item.turnSpeed = tonumber(setting.TurnSpeed)
        item.straightenSpeed = tonumber(setting.StraightenSpeed)
        item.moveSpeed = tonumber(setting.MoveSpeed)
        item.waitStraightenTime = tonumber(setting.WaitStraightenTime)
        item.cameraOffset = VectorUtil.newVector3(setting.CameraOffsetX, setting.CameraOffsetY, setting.CameraOffsetZ)
        item.cameraRotCenterOffset = VectorUtil.newVector3(setting.CameraRotCenterOffsetX, setting.CameraRotCenterOffsetY, setting.CameraRotCenterOffsetZ)
        item.riderRenderOffset = VectorUtil.newVector3(setting.RiderRenderOffsetX, setting.RiderRenderOffsetY, setting.RiderRenderOffsetZ)
        item.riderRenderOrientation = { w = tonumber(setting.RiderRenderOrientationW), x = tonumber(setting.RiderRenderOrientationX),
                                        y = tonumber(setting.RiderRenderOrientationY), z = tonumber(setting.RiderRenderOrientationZ) }
        item.modelName = setting.ModelName
        item.mountBone = setting.MountBone
        item.headTextOffset = tonumber(setting.HeadTextOffset)
        item.maxCameraBodyAngle = tonumber(setting.MaxCameraBodyAngle) * MathUtil.DEG2RAD
        item.scale = tonumber(setting.Scale)
        item.rideAnimation = setting.RideAnimation
        item.penetrateBlocks = (setting.PenetrateBlocks ~= "0")
        item.spawnSoundId = tonumber(setting.SpawnSoundId)
        item.deadSoundId = tonumber(setting.DeadSoundId)
        item.takingSoundId = tonumber(setting.TakingSoundId)
        item.yOffset = tonumber(setting.Yoffset)
        MountSetting.addSetting(item)
    end
end